INSERT INTO nursing_task (
    nursing_id, task_type, status, elder_id, project_id, bed_number,
    estimated_server_time, real_server_time, mark, task_image, cancel_reason, rel_no,
    create_time, update_time, create_by, update_by, remark
) VALUES (
    #{nursingId}, #{taskType}, #{status}, #{elderId}, #{projectId}, #{bedNumber},
    #{estimatedServerTime}, #{realServerTime}, #{mark}, #{taskImage}, #{cancelReason}, #{relNo},
    #{createTime}, #{updateTime}, #{createBy}, #{updateBy}, #{remark}
)

mapper.update:
UPDATE nursing_task
nursing_id = #{nursingId}, status = #{status}, bed_number = #{bedNumber}, estimated_server_time = #{estimatedServerTime}, real_server_time = #{realServerTime}, mark = #{mark}, task_image = #{taskImage}, cancel_reason = #{cancelReason}, rel_no = #{relNo}, remark = #{remark}, update_time = #{updateTime}, update_by = #{updateBy},
WHERE id = #{id}

mapper.select:
SELECT nt.id, nt.nursing_id, nt.project_id, nt.elder_id, nt.task_type, nt.estimated_server_time, nt.real_server_time, nt.mark, nt.cancel_reason, nt.status, nt.rel_no, nt.task_image, nt.create_time, nt.update_time, nt.create_by, nt.update_by, nt.remark, e.name AS elder_name, e.id_card_no, e.image, e.sex, cc.nursing_level_name AS lname, COALESCE(nt.bed_number, e.bed_number, b.bed_number) AS bed_number, np.name AS project_name, su_create.real_name AS creator, su_update.real_name AS updater FROM nursing_task nt LEFT JOIN elder e ON nt.elder_id = e.id LEFT JOIN bed b ON e.bed_id = b.id LEFT JOIN nursing_project np ON nt.project_id = np.id LEFT JOIN sys_user su_create ON nt.create_by = su_create.id LEFT JOIN sys_user su_update ON nt.update_by = su_update.id LEFT JOIN check_in ci ON ci.elder_id = nt.elder_id AND ci.status = 0 LEFT JOIN check_in_config cc ON cc.check_in_code = ci.check_in_code
AND EXISTS ( SELECT 1 FROM nursing_elder ne2 WHERE ne2.elder_id = nt.elder_id AND ne2.nursing_id = #{nurseId} )
AND nt.project_id = #{projectId}
AND e.name LIKE CONCAT('%', #{elderName}, '%')
AND nt.status = #{status}
AND nt.estimated_server_time >= #{startTime}
AND nt.estimated_server_time <= #{endTime}
ORDER BY nt.estimated_server_time ASC, nt.id ASC

SELECT COUNT(1) FROM nursing_task
WHERE elder_id = #{elderId}
  AND project_id = #{projectId}
  AND estimated_server_time = #{estimatedServerTime}
  AND task_type = 2
